define('taoMediaManager/qtiCreator/widgets/static/img/Widget',['jquery', 'taoQtiItem/qtiCreator/widgets/static/Widget', 'taoMediaManager/qtiCreator/widgets/static/img/states/states', 'taoQtiItem/qtiCreator/widgets/static/helpers/widget', 'tpl!taoQtiItem/qtiCreator/tpl/toolbars/media', 'taoQtiItem/qtiCreator/widgets/static/helpers/inline', 'ui/mediaEditor/plugins/mediaAlignment/helper'], function ($, Widget, states, helper, toolbarTpl, inlineHelper, alignmentHelper) {
  'use strict';

  var ImgWidget = Widget.clone();
  ImgWidget.initCreator = function initCreator(options) {
    var img = this.element;
    this.registerStates(states);
    Widget.initCreator.call(this);
    inlineHelper.togglePlaceholder(this);
    alignmentHelper.initAlignment(this);
    inlineHelper.checkFileExists(this, img, 'src', options.baseUrl);
    $('#item-editor-scope').on("filedelete.resourcemgr.".concat(this.element.serial), (e, src) => {
      if (this.getAssetManager().resolve(img.attr('src')) === this.getAssetManager().resolve(src)) {
        img.attr('src', '');
        inlineHelper.togglePlaceholder(self);
      }
    });
  };
  ImgWidget.destroy = function destroy() {
    $('#item-editor-scope').off(".".concat(this.element.serial));
  };
  ImgWidget.getRequiredOptions = function getRequiredOptions() {
    return ['baseUrl', 'uri', 'lang', 'mediaManager', 'assetManager'];
  };
  ImgWidget.buildContainer = function buildContainer() {
    helper.buildInlineContainer(this);
    this.$container.css({
      width: this.element.attr('width'),
      height: this.element.attr('height')
    });
    if (this.$original[0]) {
      this.$original[0].setAttribute('width', '100%');
      this.$original[0].removeAttribute('height');
    }
    return this;
  };
  ImgWidget.createToolbar = function createToolbar() {
    helper.createToolbar(this, toolbarTpl);
    return this;
  };
  return ImgWidget;
});
