define('taoMediaManager/qtiCreator/helper/formatStyles',['jquery'], function ($) {
  'use strict';

  function handleStylesheetLoad(e) {
    var path = e && e.composedPath && e.composedPath();
    var linkTag = path[0];
    if (linkTag) {
      var stylesheetUrl = linkTag.href.split('&stylesheet=');
      var rdf_styles = stylesheetUrl[0].split('%23').reverse()[0];
      var assets = $("[data-identifier='".concat(rdf_styles, "']"));
      if (assets.length) {
        assets.each((h, asset) => {
          var assetClassName = asset.children[0].className.match(/[\w-]*tao-[\w-]*/g) || asset.children[1].className.match(/[\w-]*tao-[\w-]*/g);
          if (assetClassName) {
            _formatStyles(linkTag.sheet, assetClassName[0]);
          } else {
            _hideStyles(linkTag.sheet);
          }
        });
        return;
      }
      var stylesheetSerial = linkTag.dataset.serial;
      var passagesItem = $("div[data-serial*='".concat(stylesheetSerial, "']"));
      if (passagesItem.length) {
        passagesItem.each((h, passages) => {
          var passageWrapper = $(passages).find('.qti-include > div');
          var passageItemClassName = passageWrapper[0] && passageWrapper[0].className && passageWrapper[0].className.match(/[\w-]*tao-[\w-]*/g);
          if (passageItemClassName) {
            _formatStyles(linkTag.sheet, passageItemClassName[0]);
          }
        });
        return;
      }
      var passagesPreview = $("[data-href*='".concat(rdf_styles, "']"));
      if (passagesPreview.length) {
        passagesPreview.each((h, passages) => {
          var passagePreviewClassName = passages.className.match(/[\w-]*tao-[\w-]*/g);
          if (passagePreviewClassName) {
            _formatStyles(linkTag.sheet, passagePreviewClassName[0]);
          }
        });
        return;
      }
    }
  }
  function _hideStyles(linkTag) {
    var {
      cssRules
    } = linkTag || {};
    var CSSStyleSheet = linkTag || {};
    if (cssRules) {
      Object.values(cssRules).map((index, rule) => {
        CSSStyleSheet.deleteRule(index);
      });
    }
    return;
  }
  function _formatStyles(linkTag, className) {
    var {
      cssRules
    } = linkTag || {};
    var CSSStyleSheet = linkTag || {};
    var classNameFormated = className && className.length ? ".".concat(className) : '';
    var scopedCssRules = _scopeStyles(cssRules, classNameFormated, ['body', 'html', 'div.qti-item']);
    if (cssRules && scopedCssRules) {
      Object.values(cssRules).map((index, rule) => {
        CSSStyleSheet.deleteRule(index);
      });
      var newRules = scopedCssRules.split('\n');
      Object.values(newRules).map(rule => {
        CSSStyleSheet.insertRule(rule);
      });
    }
    return;
  }
  ;
  function _scopeStyles(cssRules, scopeSelector, toReplace, replacementSelector) {
    if (!cssRules) {
      return '';
    }
    if (!replacementSelector) {
      replacementSelector = scopeSelector;
    }
    var scopedStyles = Object.values(cssRules).map(rule => {
      if (!rule.selectorText) {
        return '';
      }
      var rulesInBrackets = rule.cssText.substr(rule.selectorText.length).trim();
      var selectors = rule.selectorText.split(/\s*,\s*/);
      var scopedSelectors = [];
      for (var singleSelectorText of selectors) {
        if (['html', 'body', 'div.qti-item'].includes(singleSelectorText)) {
          continue;
        }
        var numRepeat = 0;
        if (scopeSelector && toReplace) {
          for (var toReplaceSelector of toReplace) {
            if (singleSelectorText.includes(toReplaceSelector)) {
              if (numRepeat > 0) {
                replacementSelector = '';
              }
              singleSelectorText = singleSelectorText.replace(new RegExp(toReplaceSelector, 'ig'), replacementSelector);
              numRepeat++;
            }
          }
        }
        var containsScopeSelector = singleSelectorText.includes("".concat(scopeSelector, " ")) || singleSelectorText.startsWith(scopeSelector) || singleSelectorText.endsWith(scopeSelector);
        if (scopeSelector && !containsScopeSelector) {
          scopedSelectors.push("".concat(scopeSelector, " ").concat(singleSelectorText));
        } else {
          scopedSelectors.push(singleSelectorText);
        }
      }
      if (scopedSelectors.length) {
        return "".concat(scopedSelectors.join(','), " ").concat(rulesInBrackets);
      }
      return '';
    });
    return scopedStyles.filter(str => str.length > 0).join('\n');
  }
  return {
    handleStylesheetLoad
  };
});
