define('taoMediaManager/qtiCreator/editor/styleEditor/colorSelector',['jquery', 'lodash', 'i18n', 'taoMediaManager/qtiCreator/editor/styleEditor/styleEditor', 'taoQtiItem/qtiCreator/helper/popup', 'lib/farbtastic/farbtastic'], function ($, _, __, styleEditor) {
  'use strict';
  function rgbToHex(color) {
    function toHexPair(inp) {
      return "0".concat(parseInt(inp, 10).toString(16)).slice(-2);
    }
    if (!_.isString(color)) {
      return color;
    }
    var rgbArr = /rgb\s*\(\s*(\d{1,3})\s*,\s*(\d{1,3})\s*,\s*(\d{1,3})\s*\)/i.exec(color);
    if (!_.isArray(rgbArr) || rgbArr.length !== 4) {
      return color;
    }
    return "#".concat(toHexPair(rgbArr[1])).concat(toHexPair(rgbArr[2])).concat(toHexPair(rgbArr[3]));
  }
  function additionalStylesToObject() {
    var additional = arguments.length > 0 && arguments[0] !== undefined ? arguments[0] : '';
    var styles = {};
    var additionalStyles = additional.split(';');
    additionalStyles.forEach(element => {
      var keyValue = element.split(':');
      styles[keyValue[0]] = keyValue[1];
    });
    return styles;
  }
  var colorSelector = function colorSelector($container) {
    var colorPicker = $container.find('.item-editor-color-picker'),
      widget = colorPicker.find('.color-picker'),
      widgetBox = colorPicker.find('.color-picker-container'),
      titleElement = colorPicker.find('.color-picker-title'),
      input = colorPicker.find('.color-picker-input'),
      resetButtons = colorPicker.find('.reset-button'),
      colorTriggers = colorPicker.find('.color-trigger'),
      colorTriggerLabels = colorPicker.find('label'),
      $doc = $(document),
      additionalStyles = {};
    var currentProperty = 'color',
      widgetObj;
    var setTitle = function setTitle(property, trigger) {
      titleElement.text(trigger.parent().find('label').text());
    };
    var setTriggerColor = function setTriggerColor() {
      colorTriggers.each(function () {
        var $trigger = $(this);
        var target = styleEditor.replaceHashClass($trigger.data('target'));
        var style = styleEditor.getStyle() || {};
        var value;
        var targetOld = target.replace(' *', '');
        if (style[target] && style[target][$trigger.data('value')]) {
          value = style[target][$trigger.data('value')].replace(' !important', '');
          $trigger.css('background-color', value);
          $trigger.attr('title', rgbToHex(value));
        } else if (style[targetOld] && style[targetOld][$trigger.data('value')]) {
          value = style[targetOld][$trigger.data('value')].replace(' !important', '');
          $trigger.css('background-color', value);
          $trigger.attr('title', rgbToHex(value));
        } else {
          $trigger.css('background-color', '');
          $trigger.attr('title', __('No value set'));
        }
      });
    };
    var collectCommonAdditionalStyles = function collectCommonAdditionalStyles() {
      colorTriggers.each(function () {
        var $trigger = $(this);
        var target = styleEditor.replaceHashClass($trigger.data('target'));
        var value = $trigger.data('value');
        var styles = additionalStylesToObject($trigger.data('additional'));
        Object.keys(styles).forEach(key => {
          if (!additionalStyles[key]) {
            additionalStyles[key] = [{
              target,
              value
            }];
          } else {
            additionalStyles[key].push({
              target,
              value
            });
          }
        });
      });
    };
    widgetObj = $.farbtastic(widget).linkTo(input);
    setTriggerColor();
    collectCommonAdditionalStyles();
    colorTriggers.add(colorTriggerLabels).off('click').on('click', function () {
      var $tmpTrigger = $(this),
        $trigger = this.nodeName.toLowerCase() === 'label' ? $tmpTrigger.parent().find('.color-trigger') : $tmpTrigger;
      widget.prop('target', $trigger.data('target'));
      widget.prop('additional', $trigger.data('additional') || '');
      widgetBox.hide();
      currentProperty = $trigger.data('value');
      setTitle(currentProperty, $trigger);
      widgetObj.setColor(rgbToHex($trigger.css('background-color')));
      widgetBox.show();
      widget.on('colorchange.farbtastic', function (e, color) {
        styleEditor.apply(widget.prop('target'), currentProperty, color);
        if (widget.prop('additional')) {
          var styles = additionalStylesToObject(widget.prop('additional'));
          Object.keys(styles).forEach(key => {
            styleEditor.apply(widget.prop('target'), key, styles[key]);
          });
        }
        setTriggerColor();
      });
      $doc.on('mouseup.colorselector', function (e) {
        if ($(e.target).hasClass('closer')) {
          widgetBox.hide();
          widget.off('colorchange.farbtastic');
          $doc.off('colorselector');
          return false;
        }
        if (!widgetBox.is(e.target) && widgetBox.has(e.target).length === 0) {
          widgetBox.hide();
          widget.off('colorchange.farbtastic');
          $doc.off('colorselector');
          return false;
        }
      });
      $doc.on('keyup.colorselector', function (e) {
        if (e.keyCode === 27) {
          widgetBox.hide();
          widget.off('colorchange.farbtastic');
          $doc.off('colorselector');
          return false;
        }
      });
    });
    resetButtons.off('click').on('click', function () {
      var $this = $(this);
      var $colorTrigger = $this.parent().find('.color-trigger');
      var target = styleEditor.replaceHashClass($colorTrigger.data('target'));
      var value = $colorTrigger.data('value');
      var additional = $colorTrigger.data('additional');
      styleEditor.apply(target, value);
      if (additional) {
        var styles = additionalStylesToObject(additional);
        Object.keys(styles).forEach(key => {
          if (additionalStyles[key].length === 1) {
            styleEditor.apply(target, key);
          } else {
            var style = styleEditor.getStyle() || {};
            var needToRemove = true;
            additionalStyles[key].forEach(element => {
              if ((target !== element.target || value !== element.value) && style[target] && style[element.target][element.value]) {
                needToRemove = false;
              }
            });
            if (needToRemove) {
              styleEditor.apply(target, key);
            }
          }
        });
      }
      setTriggerColor();
    });
    $doc.on('customcssloaded.styleeditor', setTriggerColor);
  };
  return colorSelector;
});
