define('taoMediaManager/qtiCreator/editor/styleEditor/fontSizeChanger',['jquery', 'lodash', 'taoMediaManager/qtiCreator/editor/styleEditor/styleEditor'], function ($, _, styleEditor) {
  'use strict';
  var fontSizeChanger = function fontSizeChanger($container) {
    var $fontSizeChanger = $container.find('#item-editor-font-size-changer');
    var itemSelector = styleEditor.replaceHashClass($fontSizeChanger.data('target'));
    itemSelector = styleEditor.replaceHashClass(itemSelector);
    var figcaptionSelector = "".concat(itemSelector, " figure figcaption");
    var $resetBtn = $fontSizeChanger.parents('.reset-group').find('[data-role="font-size-reset"]');
    var $input = $container.find('.item-editor-font-size-text');
    var itemFontSize = parseInt($(itemSelector).css('font-size'), 10) || 14;
    var styles = styleEditor.getStyle() || {};
    var itemSelectorOld = itemSelector.replace(' *', '');
    if (styles[itemSelector] && styles[itemSelector]['font-size']) {
      itemFontSize = parseInt(styles[itemSelector]['font-size'], 10);
      $input.val(itemFontSize);
    } else if (styles[itemSelectorOld] && styles[itemSelectorOld]['font-size']) {
      itemFontSize = parseInt(styles[itemSelectorOld]['font-size'], 10);
      $input.val(itemFontSize);
    } else {
      $input.val('');
    }
    var resizeFont = function resizeFont() {
      styleEditor.apply(itemSelector, 'font-size', "".concat(itemFontSize.toString(), "px"));
      var figcaptionSize = itemFontSize > 14 ? (itemFontSize - 2).toString() : Math.min(itemFontSize, 12).toString();
      styleEditor.apply(figcaptionSelector, 'font-size', "".concat(figcaptionSize, "px"));
    };
    $fontSizeChanger.find('button').off('click').on('click', function (e) {
      e.preventDefault();
      if ($(this).data('action') === 'reduce') {
        if (itemFontSize <= 10) {
          return;
        }
        itemFontSize--;
      } else {
        itemFontSize++;
      }
      resizeFont();
      $input.val(itemFontSize);
      $(this).parent().blur();
    });
    $input.off('blur').on('blur', function () {
      if (this.value) {
        itemFontSize = parseInt(this.value, 10);
        resizeFont();
      } else {
        styleEditor.apply(itemSelector, 'font-size');
        styleEditor.apply(figcaptionSelector, 'font-size');
      }
    });
    $input.off('keydown').on('keydown', function (e) {
      var c = e.keyCode;
      if (c === 13) {
        $input.trigger('blur');
      }
      return _.includes([8, 37, 39, 46], c) || c >= 48 && c <= 57 || c >= 96 && c <= 105;
    });
    $resetBtn.off('click').on('click', function () {
      styleEditor.apply(itemSelector, 'font-size');
      styleEditor.apply(figcaptionSelector, 'font-size');
      $input.val('');
      itemFontSize = parseInt($(itemSelector).css('font-size'), 10);
    });
    $(document).on('customcssloaded.styleeditor', function (e, style) {
      if (style[itemSelector] && style[itemSelector]['font-size']) {
        itemFontSize = parseInt(style[itemSelector]['font-size'], 10);
        $input.val(itemFontSize);
      } else if (style[itemSelectorOld] && style[itemSelectorOld]['font-size']) {
        itemFontSize = parseInt(style[itemSelectorOld]['font-size'], 10);
        $input.val(itemFontSize);
      } else {
        $input.val('');
      }
    });
  };
  return fontSizeChanger;
});
