define('taoMediaManager/qtiCreator/editor/styleEditor/fontSelector',['jquery', 'lodash', 'json!taoQtiItem/qtiCreator/editor/resources/font-stacks.json', 'taoMediaManager/qtiCreator/editor/styleEditor/styleEditor', 'i18n', 'select2'], function ($, _, fontStacks, styleEditor, __) {
  'use strict';
  var fontSelector = function fontSelector($container) {
    var selector = 'select#item-editor-font-selector',
      $selector = $container.find(selector);
    var target = styleEditor.replaceHashClass($selector.data('target'));
    var normalize = function normalize(font) {
        return font.replace(/"/g, "'").replace(/, /g, ',');
      },
      clean = function clean(font) {
        return font.substring(0, font.indexOf(',')).replace(/'/g, '').replace(/"/g, '');
      },
      resetButton = $selector.parent().find('[data-role="font-selector-reset"]'),
      toLabel = function toLabel(font) {
        font = font.replace(/-/g, ' ');
        return font.replace(/^([a-z\u00E0-\u00FC])|\s+([a-z\u00E0-\u00FC])/g, function ($1) {
          return $1.toUpperCase();
        });
      },
      format = function format(state) {
        var originalOption = state.element;
        if (!state.id) {
          return state.text;
        }
        return "<span style=\"font-size: 12px;".concat($(originalOption).attr('style'), "\">").concat(state.text, "</span>");
      },
      reset = function reset() {
        styleEditor.apply(target, 'font-family');
        $selector.select2('val', '');
      };
    var applyToStylesEditor = true;
    $selector.empty();
    $selector.append("<option value=\"\">".concat(__('Default'), "</option>"));
    var styles = styleEditor.getStyle() || {};
    var selectedFontFamily = styles[target] && styles[target]['font-family'] && clean(styles[target]['font-family']);
    _.forEach(fontStacks, (value, key) => {
      var optGroup = $('<optgroup>', {
        label: toLabel(key)
      });
      _.forEach(value, font => {
        var normalizeFont = normalize(font);
        var option = $('<option>', {
          value: normalizeFont,
          text: clean(normalizeFont)
        }).css({
          fontFamily: normalizeFont
        });
        if (clean(normalizeFont) === selectedFontFamily) {
          option.attr('selected', true);
        }
        optGroup.append(option);
      });
      $selector.append(optGroup);
    });
    resetButton.off('click').on('click', reset);
    $selector.select2({
      formatResult: format,
      formatSelection: format,
      width: 'resolve'
    });
    $selector.off('change').on('change', function () {
      if (applyToStylesEditor) {
        styleEditor.apply(target, 'font-family', $(this).val());
      } else {
        applyToStylesEditor = true;
      }
    });
    $(document).on('customcssloaded.styleeditor', function (e, style) {
      if (style[target] && style[target]['font-family']) {
        $selector.select2('val', style[target]['font-family'].replace(' !important', ''));
        $("".concat(selector, " option:selected")).first().attr('selected', 'selected');
      }
      applyToStylesEditor = false;
      $selector.trigger('change');
    });
  };
  return fontSelector;
});
